import { readFile, writeFile } from "node:fs/promises";

const sources = [
  "src/idleUiState.js",
  "src/animationCatalog.js",
  "src/game.js"
];

const chunks = [];

for (const path of sources) {
  let source = await readFile(new URL(`../${path}`, import.meta.url), "utf8");
  source = source
    .replace(/^\s*import[\s\S]*?from\s+["'][^"']+["'];\r?\n?/gm, "")
    .replace(/^export /gm, "");
  chunks.push(`// ${path}\n${source}`);
}

const banner = [
  "/*",
  " * Generated by scripts/build-bundle.mjs.",
  " * Keeps index.html playable from file:// without ES module loading.",
  " */",
  ""
].join("\n");

await writeFile(new URL("../src/game.bundle.js", import.meta.url), `${banner}${chunks.join("\n\n")}\n`, "utf8");
